# Generate a large Russian trivia question bank in BogusTrivia format:
#   question*answer1*answer2*...
# Includes normal trivia (auto-generated from fact tables) + a large curated
# block of crude / adult "пошлые загадки" per deemah's request.

Q = []
_seen = set()

def add(question, *answers):
    q = question.strip()
    ans = [a.strip() for a in answers if a.strip()]
    if not q or not ans:
        return
    key = q.lower()
    if key in _seen:
        return
    _seen.add(key)
    Q.append(q + "*" + "*".join(ans))

